const Q_IRK_2003=[{"id": "objective>IRK>2003>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The forms of revelations are explained in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q. 40:51 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 41:50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 42:51 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 43:50</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Forms of revelation  <br/>  I. Behind the viel (warai Hijab)  <br/>  ii. Revelation/Inspiration (Wahyum)  <br/>  iii. Through Angel (Malek (Angel Jitrip))</div>", "topic": "THE QUR'AN AND HADITH - REVELATION OF THE GLORIOUS QUR'AN : DIFFERENT MODES OF REVELATION: INSPIRATION BEHIND THE VEIL, THROUGH AN ANGEL, ETC."}, {"id": "objective>IRK>2003>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The initial idea to preserve the Glorious Qur'an was mooted by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AbuBakr As-Saddiq</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Umar b.Khattab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zaid b. Thabit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uthman b. Affan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Umar bu Khatab mooted idea of compilation of the colonous Quran to preserve it because a lot of Itufaz (memorization of the Quran) were killed at the battle of Yamahah.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : THE ROLE PLAYED BY THECOMPANIONS OF THE PROPHET (SAW)"}, {"id": "objective>IRK>2003>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of Tafstr which uses the Qur'an to explain the Qur'an began during the time of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prophet (S.A.W) </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahabah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tabi'un </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tabi'u-tabi'un</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because the prophet himself used some portion of the Quran to explain the others for the purpose of clarity.</div>", "topic": "TAFSIR : HISTORICAL DEVELOPMENT OF TAFSIR"}, {"id": "objective>IRK>2003>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important use of Tafstr of Glorious Qur'an is in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">proper understanding of the message</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acknowledgement of the spiritual value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">application of the legal provisions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interpretation of the moral principle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tafsir means interpretation or detailed explanantion of the Quran.</div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2003>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Tafsir of the Glorious Qur'an which is modern in its approach to commentary is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">at-tasstr bir-r'ay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tafstr al-ma'thur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tafstr al-madhahib</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-tafstr al-'asri</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At tafsir bir-ray means interpretation of the Quran with reasoning i.e. Application of science and logic to explain the verses of the Quran.</div>", "topic": "TAFSIR : IMPORTANCE AND TYPES OF TAFSIR"}, {"id": "objective>IRK>2003>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suratul-Fatihah is also referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Suratul-Hidayah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kitabul-mathani</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ummul-kitab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Suratud-du'a</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Suraful fatihah has the following names -  <br/>  1. Ummul kitab (mother of book)  <br/>  2. Sab' ul mathani (Seren repeated verses)</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-FATIHAH"}, {"id": "objective>IRK>2003>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> is followed by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Here is the elaboration on the correct option chosen <img src=\"2003/option7c.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2003>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Suratul-Kawthar was revealed because of the Makkans'</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insinuation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">resistance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intolerance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">persecution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Suratul-Kawthar was revealed because of the Makkans' insinuation. The Surah takes its name from the word al-Kawthar in the first verse. This is an early Meccan Surah, and it was revealed in response to the Makkans' insinuation against the Prophet.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL -KAWTHAR"}, {"id": "objective>IRK>2003>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Allah swears by the Fig and the Olive in Surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Zilzal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-Trn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Qadr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-A'laq</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surat At-Tin (Q95) – The Chapter of the Fig contains 8 verses and highlights the nobility of human creation and the consequences of disbelief.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AT-TIN"}, {"id": "objective>IRK>2003>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The people described as Sharrul-bariyyah in Suratul-Bayyinah are the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jews and Christian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ahlul-kitab and mushrikun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkan unbelievers and polytheists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kuffar and the munafiqun</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 98:6 (Surat Al-Bayyinah, verse 6): <br/>  <br/> Arabic: <br/> إِنَّ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ وَٱلْمُشْرِكِينَ فِى نَارِ جَهَنَّمَ خَـٰلِدِينَ فِيهَا ۚ أُو۟لَـٰٓئِكَ هُمْ شَرُّ ٱلْبَرِيَّةِ <br/>  <br/> Transliteration: <br/> Inna alladhīna kafarū min ahlil-kitābi wal-mushrikīna fī nāri jahannama khālidīna fīhā, ūlā'ika hum sharru al-bariyyah. <br/>  <br/> Translation: <br/> \"Indeed, those who disbelieved among the People of the Book and the polytheists will be in the Fire of Hell, abiding therein forever. Those are the worst of creatures.\"</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-BAYYINAH"}, {"id": "objective>IRK>2003>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ayatul-Kursiyy not only teaches the oneness of Allah but also emphasizes His</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Eternity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Predominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Omnipresence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wisdom</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ayatul-Kursiyy, also known as the Throne Verse, is a verse from the Quran (2:255) that speaks about Allah's sovereignty, knowledge, and power. It emphasizes the concept of Allah's eternity, meaning His existence is without beginning or end. The other options, while they may be attributes of Allah, are not the primary focus of Ayatul-Kursiyy.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AYATUL-KURSIY"}, {"id": "objective>IRK>2003>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Taqrir, as a kind of Sunnah, means the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sayings of the Prophet (S.A.W) on religious matters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">action or practice of the Prophet(S.A.W)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct approach of the Prophet (S.A.W) to issues</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prophet's (S.A.W) silent approval of the actions of others</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prophets' (SAW) silence approval of the action of others is a branch of sunnah.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2003>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principles of Hadith criticism developed through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isnad and musannaf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">matn and riwayah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isnad and matn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">musnad and musannaf</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is through matu (content) ans also Isnad (chains of tranmission as components of hadith can be used to criticise it.).</div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2003>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The author of the Muwatta was the Imam</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Darus-Salam </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Darul-Hijrah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Makkah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Damascus</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Imam Malik bu Anas is the author of Mawatta. He is otherwise known as Imamu Darul Aijah (i.e Imam of Madinah).</div>", "topic": "HADITH : MUWATTA AND ITS AUTHOR – THE BIOGRAPHY OF IMAM MALIK AND THE STUDY OF HIS BOOK"}, {"id": "objective>IRK>2003>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 34 of an-Nawawi teaches that a good Muslim should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">keep away from wrongdoing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">repent of wrongdoing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">speak against wrongdoing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">always pray against any wrongdoing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hadith says, \"whosoever sees wrong doing should correct it with his hand, tongue and heart. </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : ENJOINING WHAT IS GOOD AND FORBIDDING WHAT IS WRONG HADITH 25 AND 34 OF AN NAWAWI"}, {"id": "objective>IRK>2003>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main emphasis of Hadith 19 of an-Nawawi is that one should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">give unflinching support to the authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">have strong faith in Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recognize Allah as the creator of the universe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recognize the importance of one's community</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 19 of an-Nawawi emphasizes that one should have strong faith in Allah. It teaches that a Muslim should be steadfast in their faith and trust in Allah's wisdom and plan.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2003>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W) says: If one of you takes rope (goes to the bush) and comes back with a bunch of firewood, sells it is better than begging for alms. The Hadith above focuses on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dedication to service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dignity of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decent living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muslim responsibility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hadith mentioned in the question focuses on the dignity of labour. It encourages Muslims to earn a living through honest means, rather than resorting to begging. This Hadith promotes self-reliance and the dignity that comes from working for one's sustenance.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : DIGNITY OF LABOUR (Q.62:10) (Q.78:11) HADITH FROM BUKHARI AND IBNMAJAH: “THAT ONE OF YOU TAKES HIS ROPE…….” “NEVER HAS ANYONE OF YOU EATEN…..”."}, {"id": "objective>IRK>2003>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The final and total prohibition of intoxicants is contained in Surah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Baqarah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Imran</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an-Nisa </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-Maidah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The final and total prohibition of intoxicants is contained in Surah al-Maidah (The Table Spread), verse 90. This verse explicitly prohibits the consumption of alcohol and gambling, stating that these are impure acts of Satan's handiwork.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR’AN AND HADITH : PROHIBITION OF BRIBERY AND CORRUPTION (Q:2:188), ALCOHOL AND GAMBLING (Q.2:219) (Q.5:93-94), STEALING AND FRAUD (Q.5:41) (83:1-5),SMOKING, DRUG ABUSE AND OTHER INTOXICANTS (Q.2:172-173, 195 AND 219) (Q.4:43) (Q.5:3) (Q.6:118-121) ARROGANCE (Q.31:18-19) AND EXTRAVAGANCE (Q.17:26-27) (Q.31:18-19)"}, {"id": "objective>IRK>2003>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount that may be stolen to warrant cutting off the hand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 Dinar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1 Dinar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/2 Dinar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1/4 Dinar</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1/4 Dinar in Zakah context: <br/>  <br/> In Islamic jurisprudence, ¼ (one-quarter) of a Dinar is the Nisab threshold (minimum amount) that makes stolen items liable for the hadd punishment (fixed legal penalty for theft).</div>", "topic": "FAMILY MATTERS : INHERITANCE"}, {"id": "objective>IRK>2003>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above warns the Muslim Ummah against</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carelessness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disunity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intolerance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">impatience</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse centres on disunity as a destruction and disgrace to the Ummah .</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : UNITY AND BROTHERHOOD HADITH 35 OF AN-NAWAWI"}, {"id": "objective>IRK>2003>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Forbidding Munkar in Islam means discouraging others from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">abominable acts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">injustice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">waywardness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double standard</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, 'Munkar' refers to all that is reprehensible or evil in the sight of Allah. This includes all forms of abominable acts, injustice, waywardness, and double standards. However, the term is most commonly used to refer to abominable acts, making option 1 the most accurate.</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : ENJOINING WHAT IS GOOD AND FORBIDDING WHAT IS WRONG HADITH 25 AND 34 OF AN NAWAWI"}, {"id": "objective>IRK>2003>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As Allah's creative work is discussed in Q.27:59-64, the passage intermittently cautions man against</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">distrust </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disobedience</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extravagance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploitation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The passage Q.27:59-64 in the Quran discusses Allah's creative work and intermittently cautions man against disobedience. It emphasizes the importance of obeying Allah's commands and refraining from actions that go against His will.</div>", "topic": "ARTICLE OF FAITH : HIS BOOKS"}, {"id": "objective>IRK>2003>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q6:53 indicates that the Book given to Prophet Musa (AS) serves as a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">criterion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">healer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protector </div>", "<div style=\"font-family:Cambria;font-size:17px;\">guide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Q6:53 in the Quran indicates that the Book given to Prophet Musa (AS) serves as a guide. It provides guidance on how to live a righteous life in accordance with Allah's commands.</div>", "topic": "ARTICLE OF FAITH : HIS BOOKS"}, {"id": "objective>IRK>2003>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"Verily when He intends a thing His command is 'Be' and it 'is'(Q.36:82). <br/>  From this Qur'anic passage derives the Muslim belief in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">predestination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fatalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">providence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">premonition</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Belief in predestination is part of article of faith.</div>", "topic": "ARTICLE OF FAITH : DESTINY: DISTINCTION BETWEEN QADA AND QADAR"}, {"id": "objective>IRK>2003>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Muslim who converts to another religion is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mushrik </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mulhid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Munafid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Murtadd</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Muslim who converts to another religion is known as a Murtadd. The term Murtadd is used in Islamic law to refer to an apostate, a person who has, through words, actions, or by implication, renounced their faith in Islam.</div>", "topic": "TAWHID AND FIQH : FAITH"}, {"id": "objective>IRK>2003>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Taharah is a symbolic preparation of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soul </div>", "<div style=\"font-family:Cambria;font-size:17px;\">body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clothes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">place</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Taharah means purification from physical and spiritual filth.</div>", "topic": "IBADAT AND THEIR TYPES : TAHARAH, ITS TYPES AND IMPORTANCE AL-ISTINJA'/ISTIJMAR, ALWUDU', AT-TAYAMMUM AND AL-GHUSL HADITH 10 AND 23 OF AN-NAWAWI"}, {"id": "objective>IRK>2003>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A special prayer that has no iqamah, ruku or sujud is known as Salah</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Khawf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-istisqd</div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-jandzah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">al-khusuf</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A special prayer that has no iqamah, ruku or sujud is known as Salah al-jandzah. Salah al-jandzah, or the funeral prayer, is a part of the Islamic funeral ritual. The prayer is performed in congregation to seek pardon for the deceased and all dead Muslims.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2003>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Zakah which is given at the end of fasting is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">voluntary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an emphatic sunnah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compulsory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a commendable act</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Zakah which is given at the end of fasting is compulsory. This is known as Zakat al-Fitr, and it is a form of alms-giving treated in Islam as a religious obligation or tax, which, by Quranic ranking, is next after prayer in importance.</div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>2003>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fasting on the day of doubt is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">forbidden </div>", "<div style=\"font-family:Cambria;font-size:17px;\">allowed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obligatory </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supererogatory</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is not allowed to fast on the day of doubt i.e. 30th Day of Shaban and last 2 days because of doubt.</div>", "topic": "IBADAT AND THEIR TYPES : SAWM"}, {"id": "objective>IRK>2003>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The 8th day of Dhul hijjah is called Yaum</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Arafah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tasua</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ashura </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at-Tarwiyah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Yaum at-Tarwiyah is the 8th day of Dhul-Itijah in which all prigrims move out of Makkah to Mina to commence actual Hajj rites.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>2003>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The legal statue of Jihad in Islam is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fard'ain </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mustahabb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mubah </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fard kifayah</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">fard kifayah means \"compulsory in which if some set of people have done it, it covers for the others\". </div>", "topic": "IBADAT AND THEIR TYPES : JIHAD"}, {"id": "objective>IRK>2003>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Marriage is referred to in Q. 4:21 as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mirhaq </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nikah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ijbar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">khitbah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marriage is referred to in Q. 4:21 as mirhaq. This term is used to denote the binding nature of the marriage contract.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2003>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q.4:34 enjoins the wife not only to be obedient but also to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maintain her chastity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">protect her home</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defend her rights</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endure all difficulties</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maintenance of chastity is part of wife duties and responsibilities</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2003>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the contributions of Islam to women welfare is the introduction of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inheritance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">family planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marriage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">women seclusion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In islamic principles of inheritance, specific portions are alloted for women (as wives, mother, daughter and sibling of the deceased person, where as, before Islam letter or not was alloted for women because they were considered as property).</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2003>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\".. the parties should either hold together on equitable terms or...\" (Q.2:229)  <br/>  This verse of the Glorious Qur'an stresses the need for a Muslim to be kind to his wife at the time of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divorce </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disagreement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pregnancy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distress</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The verse Q.2:229 from the Qur'an is about divorce. It emphasizes the importance of treating each other kindly and fairly during the process of divorce. Therefore, the correct answer is 'divorce'.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2003>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Talaq al bain means divorce that is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">revocable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">permissible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detestable </div>", "<div style=\"font-family:Cambria;font-size:17px;\">irrevocable</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Talaq al bain refers to an irrevocable divorce in Islamic law. Once this type of divorce has been declared, the couple cannot remarry unless the woman marries another man, the marriage is consummated, and then the second husband dies or divorces her.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2003>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ra'y as a mode of Ijtihad technically means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">considered opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debated opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">respected opinion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free opinion</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ra'y as a mode of Ijtihad technically means 'considered opinion'. Ijtihad is an Islamic legal term that refers to independent reasoning or the thorough exertion of a jurist's mental faculty in finding a solution to a legal question. Ra'y is one of the methods used in Ijtihad.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR SUNNI SCHOOLS OF LAW"}, {"id": "objective>IRK>2003>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A feature which is common to the Shari'ah and the common law is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rigidity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flexibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">credibility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inimitability</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both divine and natural laws are credible and must be upheld.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR MAJOR SOURCES THE QUR'AN, SUNNAH, IJMA AND QIYAS"}, {"id": "objective>IRK>2003>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference among the Sunni schools of law borders on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">jurisprudential interpretation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judicial rulings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal application</div>", "<div style=\"font-family:Cambria;font-size:17px;\">customary usage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major difference among the Sunni schools of law borders on jurisprudential interpretation. This refers to the different ways in which the schools interpret Islamic law and jurisprudence. Judicial rulings, legal application, and customary usage are not the major differences among the Sunni schools of law.</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR SUNNI SCHOOLS OF LAW"}, {"id": "objective>IRK>2003>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most popular means of alleviating poverty in the Muslim society is through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">baitul-mal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zakah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rawatib </div>", "<div style=\"font-family:Cambria;font-size:17px;\">waqf</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zakah is one of the five pillars of Islam and is a religious obligation for all Muslims who meet the necessary criteria of wealth. It is a mandatory charitable contribution, often considered to be a tax, that serves as a basis for Muslim society's welfare system. Therefore, it is the most popular means of alleviating poverty in the Muslim society.</div>", "topic": "ISLAMIC ECONOMIC SYSTEM : BAITUL-MAL AS AN INSTITUTION OF SOCIO-ECONOMIC WELFARE"}, {"id": "objective>IRK>2003>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important right which both Muslims and non-Muslims have under the Islamic political system is that of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">worship </div>", "<div style=\"font-family:Cambria;font-size:17px;\">justice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">honour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">life</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under the Islamic political system, the most important right for both Muslims and non-Muslims is justice. Islam places a high emphasis on justice, and it is a fundamental value in Islamic law and ethics.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : ISLAMIC REFORMS"}, {"id": "objective>IRK>2003>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Prophet (S.A.W) granted general amnesty to all enemies of Islam after the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Battle of Yamamah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conquest of Makkah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Campaign of Tabuk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Battle of Hunain</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After the Conquest of Makkah, the Prophet Muhammad (S.A.W) granted general amnesty to all enemies of Islam. This was a significant event as it marked the end of the major conflict between the Muslims and the Quraysh tribe.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE TREATY OF AL-HUDAIBIYYAH AND THE CONQUEST OF MAKKAH"}, {"id": "objective>IRK>2003>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Battle of Siffin was fought under the Caliphate of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AbuBakr </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Umar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Uthman </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ali</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Battle of Siffin was fought during the caliphate because of the emergence of maawuyyah group who claimed to be interested in caliphate.</div>", "topic": "THE RIGHTLY GUIDED CALIPHS AL-KHULAFA'U RASHIDUN : THE LIVES AND CONTRIBUTIONS OF THE FOUR RIGHTLY GUIDED CALIPHS"}, {"id": "objective>IRK>2003>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Abu Bakr reigned for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2 years </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3 years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4 years </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5years</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Abu Bakr ruled for 2 years, from 632 to 634 CE.</div>", "topic": "THE RIGHTLY GUIDED CALIPHS AL-KHULAFA'U RASHIDUN : THE LIVES AND CONTRIBUTIONS OF THE FOUR RIGHTLY GUIDED CALIPHS"}, {"id": "objective>IRK>2003>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The man who established the Muslim city of Qairawan was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Uqbah b. Nafi'</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ubaidah b. Sa'ad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Irshad b. Waqas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Musa b. Naufai</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Uqbah b. Nafi' is known to have founded the city of Qairawan in Tunisia in 670 AD during the Islamic conquests. He was a general serving under the Umayyad caliphate.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE SPREAD OF ISLAM TO EGYPT"}, {"id": "objective>IRK>2003>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">By the year 1110 C.E., Andalusia had fallen under the control of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mujahidin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ansar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muhajirun </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al Murabitun</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al-Murabitun lost the control of Andalusia in 1110CE. </div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE ROLE OF TRADERS, TEACHERS, PREACHERS, MURABITUN, SUFI ORDERS AND MUJADDIDUN TO THE SPREAD OF ISLAM IN WEST AFRICA."}, {"id": "objective>IRK>2003>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the early part of Islam in West Africa, the ribat was primarily a centre for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">religious propagation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sufi indoctrination</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social reform</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fraternal movement</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the early part of Islam in West Africa, the ribat was primarily a centre for religious propagation. A ribat is a small fortification built along a frontier, often serving both military and religious purposes.</div>", "topic": "EARLY CONTACT OF ISLAM WITH AFRICA : THE ROLE OF TRADERS, TEACHERS, PREACHERS, MURABITUN, SUFI ORDERS AND MUJADDIDUN TO THE SPREAD OF ISLAM IN WEST AFRICA."}, {"id": "objective>IRK>2003>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Muhammed Bello justified Jihad against the Islamic state of Borno because of the people's tendency towards</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">syncretism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extremism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">asceticism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">formalism</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Muhammed Bello justified Jihad against the Islamic state of Borno because of the people's tendency towards syncretism. Syncretism refers to the combining of different beliefs, often while melding practices of various schools of thought.</div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : THE BATTLES OF BADR, UHUD AND KHANDAQ: CAUSES AND EFFECTS"}, {"id": "objective>IRK>2003>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The institution of learning referred to as 'ummu-d-duniyah is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">al-Azhar university</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sankore University</div>", "<div style=\"font-family:Cambria;font-size:17px;\">University of Madinah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">University of Khartoum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">al-Azhar university was referred to as Ummu Duniyah (mother of the earth) It was established during Fatimid dynasty.</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : ISLAMIC EDUCATION INSTITUTIONS: HOUSE OF WISDOM IN BAGHDAD, AL-AZHAR UNIVERSITY IN CAIRO AND NIZAMIYYAH UNIVERSITY IN BAGHDAD."}, {"id": "objective>IRK>2003>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Apart from being a renowned philosopher, Ibn Rushd was also</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a jurist </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an astronomer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a scientist </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a mathematician</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Rushd, also known as Averroes, was a renowned philosopher and also a jurist. He made significant contributions to Islamic jurisprudence and philosophy. He is known for his commentaries on Aristotle's works and for his work in law and theology.</div>", "topic": "CONTRIBUTIONS OF ISLAM TO EDUCATION : THE LIVES AND CONTRIBUTIONS OF IBN SINA, AL-GHAZALI, IBN RUSHDI, AR-RAZIO AND IBN KHALDUN TO EDUCATION."}];
